use std::collections::HashMap;

struct CredentialProcessor {
    storage: HashMap<String, String>,
}

impl CredentialProcessor {
    fn new() -> Self {
        CredentialProcessor {
            storage: HashMap::new(),
        }
    }

    fn add_credential(&mut self, user_id: &str, key_hash: &str) -> Result<(), String> {
        if self.storage.contains_key(user_id) {
            return Err(format!("User {} already exists", user_id));
        }
        self.storage.insert(user_id.to_string(), key_hash.to_string());
        Ok(())
    }

    fn verify_auth(&self, user_id: &str, provided_hash: &str) -> Result<String, String> {
        if let Some(stored_hash) = self.storage.get(user_id) {
            if stored_hash == provided_hash {
                return Ok("Authentication successful".to_string());
            } else {
                return Err("Incorrect key hash provided".to_string());
            }
        }
        Err(format!("User {} not found", user_id))
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut processor = CredentialProcessor::new();
    processor.add_credential("alice99", "abcdef123456")?;

    match processor.verify_auth("alice99", "abcdef123456") {
        Ok(msg) => println!("Success: {}", msg),
        Err(e) => eprintln!("Error during verification: {}", e),
    }

    match processor.verify_auth("alice99", "wronghash") {
        Ok(msg) => println!("Unexpected success: {}", msg),
        Err(e) => println!("Expected failure case handled: {}", e),
    }

    Ok(())
}

use std::collections::BinaryHeap;
use std::cmp::{Eq, PartialEq, Ord, PartialOrd};
use std::sync::{Arc, Mutex};
use tokio::time::{self, Duration};

#[derive(Debug, Eq, PartialEq, Clone)]
struct EmailPayload {
    priority: i32,
    content: String,
}

impl Ord for EmailPayload {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.priority.cmp(&other.priority)
    }
}

impl PartialOrd for EmailPayload {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl From<EmailPayload> for BinaryHeap<EmailPayload> {
    fn from(item: EmailPayload) -> Self {
        BinaryHeap::from([item])
    }
}

struct EmailQueue {
    queue: Mutex<BinaryHeap<EmailPayload>>,
}

impl EmailQueue {
    fn new() -> Arc<Self> {
        Arc::new(EmailQueue { queue: Mutex::new(BinaryHeap::new()) })
    }

    async fn enqueue(&self, payload: EmailPayload) {
        let mut guard = self.queue.lock().unwrap();
        guard.push(payload.clone());
        println!("Enqueued message with priority: {}", payload.priority);
    }

    fn process_next(&self) -> Option<EmailPayload> {
        let mut guard = self.queue.lock().unwrap();
        if let Some(payload) = guard.pop() {
            println!("Dispatching message...");
            Some(payload)
        } else {
            None
        }
    }
}

async fn worker_loop(queue: Arc<EmailQueue>) {
    let mut interval = time::interval(Duration::from_millis(500));
    loop {
        interval.tick().await;
        if let Some(payload) = queue.process_next() {
            println!("n--- Processing Payload ---nPriority: {}
Content Preview: {:.30}...
--------------------------n", payload.priority, payload.content);
            tokio::time::sleep(Duration::from_millis(150)).await;
        }
    }
}

#[tokio::main]
async fn main() {
    let queue = EmailQueue::new();

    let _worker = tokio::spawn(worker_loop(Arc::clone(&queue)));

    time::sleep(Duration::from_millis(100)).await;
