use std::collections::HashMap;
use std::fmt::Write;

struct JobContext {
    data: HashMap<String, String>,
    result: String,
}

impl JobContext {
    fn new() -> Self {
        JobContext { data: HashMap::new(), result: String::new() }
    }
}

fn validate_job(context: &mut JobContext) -> Result<(), String> {
    if context.data.get("api_key").is_none() || context.data.get("user_id").unwrap().is_empty() {
        return Err("Missing required headers for job execution".to_string());
    }
    Ok(())
}

fn transform_payload(context: &mut JobContext) -> Result<(), String> {
    let user_id = context.data.get("user_id").unwrap().clone();
    if !user_id.contains("::") {
        return Err("Invalid user ID format for transformation".to_string());
    }
    context.data.insert("transformed_user".to_string(), format!("Processed: {}", user_id));
    Ok(())
}

fn run_job(mut context: JobContext) -> String {
    match validate_job(&mut context) {
        Ok(_) => match transform_payload(&mut context) {
            Ok(_) => write!(&mut context.result, "Job completed successfully for user {}.", context.data.get("transformed_user").unwrap()).unwrap(),
            Err(e) => write!(&mut context.result, "Transformation failed: {}", e).unwrap(),
        },
        Err(e) => write!(&mut context.result, "Validation failed: {}", e).unwrap(),
    }
    context.result
}

fn main() {
    let mut initial_data = HashMap::new();
    initial_data.insert("api_key".to_string(), "secure-token-123".to_string());
    initial_data.insert("user_id".to_string(), "app::worker:job_xyz".to_string());

    let job_context = JobContext::new();
    let final_result = run_job(JobContext { data: initial_data, result: String::new() });
    println!("Final Pipeline Result: {}", final_result);
}

use std::io::{self, Write};
use tokio::sync::mpsc;
use futures::StreamExt;

async fn simulate_data_source(tx: mpsc::Sender<String>) {
    let messages = vec![
        "Event Startn",
        "Score Update A->Bn",
        "Interval 2 Processingn",
        "Final Tally Receivedn"
    ];

    for msg in messages {
        tokio::time::sleep(tokio::time::Duration::from_millis(300)).await;
        if tx.send(String::from(msg.trim().to_owned())).await.is_err() {
            break;
        }
    }
}

async fn process_continuation(message: String) -> Result<(), io::Error> {
    println!("Processing message: {}", message);
    // Simulate complex, non-blocking processing logic that takes time
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await; 
    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let (tx, mut rx) = mpsc::channel::<String>(32);

    tokio::spawn(simulate_data_source(tx));

    while let Some(message) = rx.recv().await {
        if message.is_empty() {
            continue;
        }
        println!("n--- Received Data Chunk ---n");
        match process_continuation(message).await {
            Ok(_) => println!("Successfully processed chunk."),
            Err(e) => eprintln!("Error during processing: {}", e),
        }
    }

    println!("nData stream exhausted. Exiting gracefully.");
    Ok(())
}

use std::time::Duration;
use tokio::time::sleep;

struct WebhookPayload { 
    url: String,
    data: Vec<f64>,
}

async fn attempt_delivery(payload: &WebhookPayload) -> Result<(), String> {
    println!("Attempting delivery to: {}", payload.url);
    if payload.data.is_empty() {
        return Err("Empty data vector".to_string());
    }
    let sum: f64 = payload.data.iter().sum();
    println!("Successfully processed matrix sum: {:.2}", sum);
    Ok(())
}

async fn dispatch_webhook(payload: WebhookPayload) -> Result<(), String> {
    const MAX_RETRIES: u32 = 3;
    let mut current_attempt = 0;

    loop {
        match attempt_delivery(&payload).await {
            Ok(_) => return Ok(()),
            Err(e) if current_attempt < MAX_RETRIES => {
                current_attempt += 1;
                let backoff_seconds = 2u64.pow(current_attempt) as u64;
                println!("Delivery failed: {}. Retrying in {} seconds...", e, backoff_seconds);
                sleep(Duration::from_secs(backoff_seconds)).await;
            }
            Err(e) => {
                return Err(format!("Permanent failure after {} attempts: {}", MAX_RETRIES, e));
            }
        }
    }
}
